SELECT COUNT(*) AS total_evaluated,
       SUM(CASE WHEN decision = 'Acceptable' THEN 1 ELSE 0 END) AS total_approved
FROM decision_outcomes;

SELECT model, buying_price 
FROM automobiles 
WHERE num_doors = 4 AND num_persons = 5 AND fuel_type = 'gas';

SELECT auto_id, user_id, rating, comments
FROM consumer_feedback
WHERE rating > 3;

SELECT DISTINCT u.user_name
FROM users u
INNER JOIN consumer_feedback cf ON u.user_id = cf.user_id;

SELECT DISTINCT u.user_name
FROM users u
JOIN consumer_feedback cf ON u.user_id = cf.user_id;

SELECT u.user_name, ud.decision_status
FROM users u
JOIN user_decisions ud ON u.user_id = ud.user_id;

SELECT auto_id
FROM automobiles
WHERE horsepower > 200;

SELECT auto_id, decision, decision_reason
FROM decision_outcomes
WHERE criteria_id = 1;

SELECT make, COUNT(*)
FROM automobiles
GROUP BY make;

SELECT * 
FROM automobiles
WHERE auto_id NOT IN (SELECT auto_id FROM decision_outcomes);

SELECT * 
FROM automobiles 
WHERE horsepower = (SELECT MAX(horsepower) FROM automobiles);
